<template>
  <div class="profile-container">
    <el-row :gutter="20">
      <el-col :span="8">
        <el-card shadow="hover" class="profile-card">
          <div class="avatar-container">
            <el-avatar :size="120" :src="userInfo.avatar">
              {{ getInitials(userInfo.name) }}
            </el-avatar>
            <div class="upload-btn">
              <el-upload
                action="#"
                :http-request="uploadAvatar"
                :show-file-list="false"
                :before-upload="beforeAvatarUpload"
              >
                <el-button size="small" icon="el-icon-camera">更换头像</el-button>
              </el-upload>
            </div>
          </div>
          <div class="user-info">
            <h3 class="user-name">{{ userInfo.name }}</h3>
            <p class="user-role">{{ userInfo.role }}</p>
          </div>
          <div class="user-stats">
            <div class="stat-item">
              <div class="stat-value">{{ userInfo.loginCount }}</div>
              <div class="stat-label">登录次数</div>
            </div>
            <div class="stat-item">
              <div class="stat-value">{{ formatDate(userInfo.lastLogin) }}</div>
              <div class="stat-label">上次登录</div>
            </div>
          </div>
        </el-card>
      </el-col>
      
      <el-col :span="16">
        <el-card shadow="hover">
          <div slot="header" class="clearfix">
            <span>个人信息</span>
          </div>
          
          <el-tabs v-model="activeTab">
            <el-tab-pane label="基本信息" name="basic">
              <el-form 
                ref="basicForm" 
                :model="basicForm" 
                :rules="basicRules" 
                label-width="100px"
                class="profile-form"
              >
                <el-form-item label="用户名" prop="username">
                  <el-input v-model="basicForm.username" disabled></el-input>
                </el-form-item>
                <el-form-item label="姓名" prop="name">
                  <el-input v-model="basicForm.name"></el-input>
                </el-form-item>
                <el-form-item label="邮箱" prop="email">
                  <el-input v-model="basicForm.email"></el-input>
                </el-form-item>
                <el-form-item label="手机号码" prop="phone">
                  <el-input v-model="basicForm.phone"></el-input>
                </el-form-item>
                <el-form-item>
                  <el-button type="primary" @click="updateBasicInfo" :loading="basicLoading">保存</el-button>
                </el-form-item>
              </el-form>
            </el-tab-pane>
            
            <el-tab-pane label="修改密码" name="password">
              <el-form 
                ref="passwordForm" 
                :model="passwordForm" 
                :rules="passwordRules" 
                label-width="100px"
                class="profile-form"
              >
                <el-form-item label="当前密码" prop="oldPassword">
                  <el-input v-model="passwordForm.oldPassword" type="password" show-password></el-input>
                </el-form-item>
                <el-form-item label="新密码" prop="newPassword">
                  <el-input v-model="passwordForm.newPassword" type="password" show-password></el-input>
                </el-form-item>
                <el-form-item label="确认密码" prop="confirmPassword">
                  <el-input v-model="passwordForm.confirmPassword" type="password" show-password></el-input>
                </el-form-item>
                <el-form-item>
                  <el-button type="primary" @click="updatePassword" :loading="passwordLoading">确认修改</el-button>
                </el-form-item>
              </el-form>
            </el-tab-pane>
            
            <el-tab-pane label="登录日志" name="logs">
              <el-table :data="loginLogs" border style="width: 100%">
                <el-table-column prop="id" label="ID" width="60"></el-table-column>
                <el-table-column prop="loginTime" label="登录时间" width="180"></el-table-column>
                <el-table-column prop="loginIp" label="登录IP" width="140"></el-table-column>
                <el-table-column prop="loginLocation" label="登录地点"></el-table-column>
                <el-table-column prop="device" label="设备信息"></el-table-column>
                <el-table-column prop="browser" label="浏览器"></el-table-column>
                <el-table-column prop="status" label="状态" width="100">
                  <template slot-scope="scope">
                    <el-tag :type="scope.row.status ? 'success' : 'danger'">
                      {{ scope.row.status ? '成功' : '失败' }}
                    </el-tag>
                  </template>
                </el-table-column>
              </el-table>
              <el-empty v-if="loginLogs.length === 0" description="暂无数据" />
            </el-tab-pane>
          </el-tabs>
        </el-card>
      </el-col>
    </el-row>
  </div>
</template>

<script>
import { mapGetters } from 'vuex'
import request from '@/api'

export default {
  name: 'Profile',
  data() {
    // 验证确认密码
    const validateConfirmPassword = (rule, value, callback) => {
      if (value !== this.passwordForm.newPassword) {
        callback(new Error('两次输入的密码不一致'))
      } else {
        callback()
      }
    }
    
    // 验证手机号
    const validatePhone = (rule, value, callback) => {
      if (value && !/^1[3-9]\d{9}$/.test(value)) {
        callback(new Error('请输入正确的手机号码'))
      } else {
        callback()
      }
    }
    
    // 验证邮箱
    const validateEmail = (rule, value, callback) => {
      if (value && !/^\w+([-+.]\w+)*@\w+([-.]\w+)*\.\w+([-.]\w+)*$/.test(value)) {
        callback(new Error('请输入正确的邮箱地址'))
      } else {
        callback()
      }
    }
    
    return {
      activeTab: 'basic',
      // 基本信息表单
      basicForm: {
        username: '',
        name: '',
        email: '',
        phone: ''
      },
      basicRules: {
        name: [
          { required: true, message: '请输入姓名', trigger: 'blur' },
          { min: 2, max: 20, message: '长度在 2 到 20 个字符', trigger: 'blur' }
        ],
        email: [
          { validator: validateEmail, trigger: 'blur' }
        ],
        phone: [
          { validator: validatePhone, trigger: 'blur' }
        ]
      },
      basicLoading: false,
      
      // 修改密码表单
      passwordForm: {
        oldPassword: '',
        newPassword: '',
        confirmPassword: ''
      },
      passwordRules: {
        oldPassword: [
          { required: true, message: '请输入当前密码', trigger: 'blur' }
        ],
        newPassword: [
          { required: true, message: '请输入新密码', trigger: 'blur' },
          { min: 6, max: 20, message: '长度在 6 到 20 个字符', trigger: 'blur' }
        ],
        confirmPassword: [
          { required: true, message: '请再次输入新密码', trigger: 'blur' },
          { validator: validateConfirmPassword, trigger: 'blur' }
        ]
      },
      passwordLoading: false,
      
      // 登录日志
      loginLogs: [],
      
      // 用户信息
      userInfo: {
        username: 'admin',
        name: '管理员',
        email: 'admin@example.com',
        phone: '13800138000',
        avatar: '',
        role: '超级管理员',
        loginCount: 286,
        lastLogin: new Date().getTime() - 24 * 60 * 60 * 1000 // 昨天
      }
    }
  },
  computed: {
    ...mapGetters(['userInfo'])
  },
  created() {
    // 初始化表单数据
    this.initFormData()
    // 获取登录日志
    this.fetchLoginLogs()
  },
  methods: {
    // 初始化表单数据
    initFormData() {
      // 从store获取用户信息
      const userInfo = this.userInfo || {}
      
      // 如果vuex中没有数据，则使用默认数据（此处使用的是模拟数据）
      this.basicForm = {
        username: userInfo.username || this.userInfo.username,
        name: userInfo.name || this.userInfo.name,
        email: userInfo.email || this.userInfo.email,
        phone: userInfo.phone || this.userInfo.phone
      }
    },
    
    // 获取用户名首字母（用于头像显示）
    getInitials(name) {
      if (!name) return 'A'
      return name.charAt(0).toUpperCase()
    },
    
    // 格式化日期
    formatDate(timestamp) {
      if (!timestamp) return '无记录'
      const date = new Date(timestamp)
      return date.toLocaleDateString('zh-CN', {
        year: 'numeric',
        month: '2-digit',
        day: '2-digit',
        hour: '2-digit',
        minute: '2-digit'
      })
    },
    
    // 上传头像前的验证
    beforeAvatarUpload(file) {
      const isImage = file.type.startsWith('image/')
      const isLt2M = file.size / 1024 / 1024 < 2
      
      if (!isImage) {
        this.$message.error('上传头像图片只能是图片格式!')
      }
      if (!isLt2M) {
        this.$message.error('上传头像图片大小不能超过 2MB!')
      }
      
      return isImage && isLt2M
    },
    
    // 自定义上传头像方法
    uploadAvatar(options) {
      const file = options.file
      // 创建一个临时的URL，用于预览
      const reader = new FileReader()
      reader.readAsDataURL(file)
      reader.onload = () => {
        // 实际项目中，这里应该调用API上传文件
        // 这里仅做演示，直接更新本地预览
        this.userInfo.avatar = reader.result
        this.$message.success('头像更新成功')
      }
    },
    
    // 更新基本信息
    updateBasicInfo() {
      this.$refs.basicForm.validate(valid => {
        if (valid) {
          this.basicLoading = true
          request({
            url: '/api/admin/profile',
            method: 'put',
            data: this.basicForm
          }).then(res => {
            if (res.code === 0) {
              this.$message.success('个人信息更新成功')
            } else {
              this.$message.error(res.message || '更新失败')
            }
          }).catch(() => {
            this.$message.error('更新失败，请稍后重试')
          }).finally(() => {
            this.basicLoading = false
          })
        }
      })
    },
    
    // 更新密码
    updatePassword() {
      this.$refs.passwordForm.validate(valid => {
        if (valid) {
          this.passwordLoading = true
          request({
            url: '/api/admin/profile/password',
            method: 'put',
            data: {
              oldPassword: this.passwordForm.oldPassword,
              newPassword: this.passwordForm.newPassword
            }
          }).then(res => {
            if (res.code === 0) {
              this.$message.success('密码修改成功，请重新登录')
              this.passwordForm = { oldPassword: '', newPassword: '', confirmPassword: '' }
            } else {
              this.$message.error(res.message || '修改失败')
            }
          }).catch(() => {
            this.$message.error('修改失败，请稍后重试')
          }).finally(() => {
            this.passwordLoading = false
          })
        }
      })
    },
    
    // 获取登录日志
    fetchLoginLogs() {
      request({
        url: '/api/admin/profile/logs',
        method: 'get',
        params: { page: 1, pageSize: 10 }
      }).then(res => {
        if (res.code === 0 && res.data) {
          this.loginLogs = res.data.list || []
        }
      }).catch(() => {
        this.loginLogs = []
      })
    }
  }
}
</script>

<style lang="scss" scoped>
.profile-container {
  padding: 20px;
  
  .profile-card {
    text-align: center;
    
    .avatar-container {
      margin-bottom: 20px;
      
      .el-avatar {
        margin-bottom: 10px;
        font-size: 48px;
      }
      
      .upload-btn {
        margin-top: 10px;
      }
    }
    
    .user-info {
      margin-bottom: 30px;
      
      .user-name {
        font-size: 20px;
        font-weight: bold;
        margin-bottom: 5px;
        color: #303133;
      }
      
      .user-role {
        font-size: 14px;
        color: #909399;
      }
    }
    
    .user-stats {
      display: flex;
      text-align: center;
      border-top: 1px solid #EBEEF5;
      padding-top: 20px;
      
      .stat-item {
        flex: 1;
        
        .stat-value {
          font-size: 18px;
          font-weight: bold;
          color: #303133;
          margin-bottom: 5px;
        }
        
        .stat-label {
          font-size: 12px;
          color: #909399;
        }
      }
    }
  }
  
  .profile-form {
    max-width: 500px;
  }
}
</style> 